                            id: v4(),
                          });
                          append({
                            amount: '200',
                            description: '',
                            id: v4(),
                          });
                        } else {
                          append({
                            amount: '',
                            description: '',
                            id: v4(),
                          });
                        }
                      }}
                      variant="secondary"
                    >
                      {!fields || fields.length === 0
                        ? t('designer.finance.amounts.enablePresets')
                        : t('designer.finance.amounts.addAmount')}
                    </Button>
                  </>
                )}
              </FieldArray>
            ) : null}
          </Stack>
